@@ -0,0 +1,15 @@
+{
+  "name": "cuf_cub_basic",
+  "description": "CSI C (CUF) moves cursor right, CSI D (CUB) moves cursor left",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b354341421b5b334458",
+  "comment": "CUF(5) to col 5, print AB at (0,5)-(0,6), CUB(3) back 3 to col 4, print X at (0,4). Cursor at (0,5).",
+  "expected": {
+    "cursor": { "row": 0, "col": 5 },
+    "cells": [
+      { "row": 0, "col": 4, "char": "X" },
+      { "row": 0, "col": 5, "char": "A" },
+      { "row": 0, "col": 6, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "cursor_clamp",
+  "description": "CUU past top and CUB past left clamp to (0,0)",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b333b354841421b5b3939411b5b393944",
+  "comment": "CUP(3,5) to (2,4), print AB at (2,4)-(2,5), CUU(99) clamps to row 0, CUB(99) clamps to col 0. Cursor at (0,0).",
+  "expected": {
+    "cursor": { "row": 0, "col": 0 },
+    "cells": [
+      { "row": 2, "col": 4, "char": "A" },
+      { "row": 2, "col": 5, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "cuu_cud_basic",
+  "description": "CSI A (CUU) moves cursor up, CSI B (CUD) moves cursor down",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b333b31481b5b324158",
+  "comment": "CUP(3,1) to (2,0), CUU(2) up 2 to (0,0), print X at (0,0). Cursor at (0,1).",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "ed_all",
+  "description": "CSI 2 J erases the entire display",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "4142431b5b32484445461b5b324a1b5b313b314858",
+  "comment": "Print ABC at (0,0)-(0,2), CUP(2) to (1,0), print DEF at (1,0)-(1,2), ED(2) erases all, CUP(1,1) to (0,0), print X. Only X remains.",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "delete_line",
+  "description": "CSI 1 M deletes a line at cursor row, shifting content up",
+  "initial_size": [5, 3],
+  "input_bytes_hex": "411b5b3248421b5b3348431b5b313b31481b5b314d",
+  "comment": "A at (0,0), CUP(2) B at (1,0), CUP(3) C at (2,0), CUP(1,1) then DL(1). Row 0 deleted, B moves to row 0, C to row 1, row 2 blank.",
+  "expected": {
+    "cursor": { "row": 0, "col": 0 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "B" },
+      { "row": 1, "col": 0, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "scroll_down_basic",
+  "description": "CSI 1 T scrolls the viewport down by one line, blanking top row",
+  "initial_size": [5, 3],
+  "input_bytes_hex": "411b5b3248421b5b3348431b5b31541b5b313b314858",
+  "comment": "A at (0,0), CUP(2) B at (1,0), CUP(3) C at (2,0), SD(1) scrolls down: row 0 blank, A to row 1, B to row 2. C falls off. CUP(1,1) X at (0,0).",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X" },
+      { "row": 1, "col": 0, "char": "A" },
+      { "row": 2, "col": 0, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "sgr_bold_dim",
+  "description": "SGR 1 enables bold, SGR 2 enables dim, SGR 0 resets all",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b316d411b5b306d1b5b326d421b5b306d43",
+  "comment": "SGR(1) bold, print A, SGR(0) reset, SGR(2) dim, print B, SGR(0) reset, print C. A is bold, B is dim, C has no attrs.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "bold": true } },
+      { "row": 0, "col": 1, "char": "B", "attrs": { "dim": true } },
+      { "row": 0, "col": 2, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "four_byte_char",
+  "description": "UTF-8 four-byte character (U+1F600 grinning face = F0 9F 98 80) prints correctly",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "41f09f988042",
+  "comment": "A + grinning face (4-byte UTF-8) + B. In this harness all chars are width 1, so cursor at col 3.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "\ud83d\ude00" },
+      { "row": 0, "col": 2, "char": "B" }
+    ]
+  }
+}
